async () => {
  const docs = await stellarDocs.search_rpc_horizon_data_docs({
    query: "simulateTransaction simulate contract invocation return fields",
    hitsPerPage: 5,
    includeContent: true
  });

  if (!docs.ok) {
    return { error: docs.error };
  }

  const hits = (docs.data.hits || []).map(h => ({
    title: h.title,
    url: h.url,
    snippet: h.snippet,
    content: h.content || ""
  }));

  const matched = hits.filter(h =>
    /simulateTransaction|simulate transaction|simulation/i.test(
      [h.title, h.snippet, h.content].join(" ")
    )
  ).slice(0, 3);

  return {
    method: "simulateTransaction",
    evidence: matched.map(h => ({ title: h.title, url: h.url, snippet: h.snippet })),
    summary: "Use the Stellar RPC method simulateTransaction to simulate a Soroban contract invocation before submission. The docs hits indicate it returns a simulation result used to prepare/inspect the transaction before sending."
  };
}

