async () => {
  const rfps = await scout.getRfps({ limit: 100 });

  const items = rfps.ok && Array.isArray(rfps.data.rfps)
    ? rfps.data.rfps
    : rfps.ok && Array.isArray(rfps.data.items)
      ? rfps.data.items
      : [];

  const norm = items.map((r) => ({
    title: r.title || r.name || null,
    slug: r.slug || null,
    status: r.status || r.state || null,
    category: r.category || null,
    url: r.url || r.link || r.href || null,
    summary: r.summary || r.description || r.brief || null,
    sponsor: r.sponsor || null,
    opensAt: r.opensAt || r.open_at || r.startDate || null,
    closesAt: r.closesAt || r.close_at || r.endDate || null,
    updatedAt: r.updatedAt || r.updated_at || null
  }));

  const relevant = norm.filter((r) => {
    const hay = [r.title, r.summary, r.category].filter(Boolean).join(' ').toLowerCase();
    return hay.includes('passkey') || hay.includes('passkeys') || hay.includes('smart account') || hay.includes('smart accounts');
  });

  const openRelevant = relevant.filter((r) => {
    const s = (r.status || '').toLowerCase();
    return s.includes('open') || s.includes('active') || s.includes('accepting');
  });

  return {
    asOf: new Date().toISOString(),
    rfpsCallOk: rfps.ok,
    totalRfpsSeen: norm.length,
    relevantCount: relevant.length,
    openRelevantCount: openRelevant.length,
    openRelevant: openRelevant.slice(0, 8),
    relevant: relevant.slice(0, 8),
    error: rfps.ok ? null : rfps.error
  };
}

