async () => {
  const results = await Promise.all([
    scout.searchProjects({ limit: 100 }),
    scout.searchProjects({ category: "Infrastructure", limit: 100 }),
    scout.searchProjects({ category: "Tooling", limit: 100 }),
    scout.searchProjects({ category: "User-Facing App", limit: 100 }),
    scout.searchProjects({ category: "Protocol/Contract", limit: 100 }),
    scout.searchProjects({ category: "Anchor", limit: 100 }),
    scout.searchProjects({ category: "Partner Integration", limit: 100 })
  ]);

  const allRows = [];
  for (const r of results) {
    if (r.ok) {
      const candidates = [r.data.projects, r.data.items, r.data.results].find(Array.isArray) || [];
      for (const p of candidates) allRows.push(p);
    }
  }

  const byKey = new Map();
  for (const p of allRows) {
    const key = p.slug || p.id || p.name || p.title;
    if (!key) continue;
    if (!byKey.has(key)) byKey.set(key, p);
  }

  const projects = Array.from(byKey.values());

  const scored = projects.map(p => {
    const devSignals = {
      githubStars: p.githubStars ?? p.github_stars ?? null,
      githubForks: p.githubForks ?? p.github_forks ?? null,
      githubOpenIssues: p.githubOpenIssues ?? p.github_open_issues ?? null,
      githubWatchers: p.githubWatchers ?? p.github_watchers ?? null,
      githubContributors: p.githubContributors ?? p.github_contributors ?? null,
      commits30d: p.commits30d ?? p.commits_30d ?? p.recentCommits ?? null,
      commits90d: p.commits90d ?? p.commits_90d ?? null,
      lastCommitAt: p.lastCommitAt ?? p.last_commit_at ?? null,
      pushedAt: p.pushedAt ?? p.pushed_at ?? null,
      updatedAt: p.updatedAt ?? p.updated_at ?? null,
      stars: p.stars ?? null,
      forks: p.forks ?? null,
      contributors: p.contributors ?? null
    };

    const numeric = Object.entries(devSignals)
      .filter(([k, v]) => typeof v === 'number' && Number.isFinite(v));

    const basis = numeric
      .sort((a, b) => b[1] - a[1])
      .slice(0, 4)
      .map(([k, v]) => ({ metric: k, value: v }));

    const recency = devSignals.lastCommitAt || devSignals.pushedAt || devSignals.updatedAt || null;
    const score = numeric.reduce((sum, [, v]) => sum + v, 0) + (recency ? 1 : 0);

    return {
      name: p.name || p.title || p.slug || p.id,
      slug: p.slug || null,
      category: p.category || null,
      status: p.status || null,
      score,
      basis,
      recency,
      sourceFieldsSeen: Object.keys(devSignals).filter(k => devSignals[k] !== null)
    };
  }).filter(p => p.basis.length > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, 5);

  return {
    searchedBuckets: results.map((r, i) => ({ index: i, ok: r.ok })),
    dedupedProjectCount: projects.length,
    top5: scored
  };
}

