  const docs = await Promise.all([
    stellarDocs.search_soroban_contract_docs({ query: "build test deploy contract", hitsPerPage: 5, includeContent: false }),
    stellarDocs.search_sdk_cli_tools_docs({ query: "stellar cli soroban test deploy", hitsPerPage: 5, includeContent: false }),
    stellarDocs.search_docs({ query: "Soroban build test deploy", hitsPerPage: 5, includeContent: false }),
    codemode.skill.read("skills.stellar-dev.smart-contracts", {
      sections: ["project-setup", "minimal-test", "build-deploy-invoke", "before-mainnet"]
    })
  ]);

  const sorobanDocs = docs[0].ok ? docs[0].data.hits.map(h => ({ title: h.title, url: h.url, section: h.section || null })) : [];
  const cliDocs = docs[1].ok ? docs[1].data.hits.map(h => ({ title: h.title, url: h.url, section: h.section || null })) : [];
  const generalDocs = docs[2].ok ? docs[2].data.hits.map(h => ({ title: h.title, url: h.url, section: h.section || null })) : [];

  let skillSections = {};
  if (docs[3].ok) {
    const s = docs[3].sections || {};
    skillSections = Object.fromEntries(
      Object.entries(s).map(([k, v]) => [k, (v || "").split("\n").slice(0, 20).join("\n")])
    );
  }

  return {
    sources: {
      sorobanDocs,
      cliDocs,
      generalDocs
    },
    skillSections
  };
}

