async () => {
  const docs = await stellarDocs.search_wallet_dapp_docs({
    query: "wallet recovery patterns",
    hitsPerPage: 8,
    includeContent: true
  });

  const walletIntegration = await codemode.skill.read("skills.stellar-dev.dapp", {
    sections: ["wallet-integration"]
  });

  const docHits = docs.ok
    ? (docs.data.hits || []).map(h => ({
        title: h.title,
        url: h.url,
        snippet: h.snippet,
        content: typeof h.content === "string" ? h.content.slice(0, 500) : undefined
      }))
    : [];

  const recoveryHits = docHits.filter(h => {
    const text = [h.title, h.snippet, h.content].filter(Boolean).join(" ").toLowerCase();
    return text.includes("recover") || text.includes("recovery") || text.includes("secret key") || text.includes("seed phrase") || text.includes("passkey");
  }).slice(0, 5);

  const skillExtract = walletIntegration.ok
    ? (walletIntegration.sections || []).map(s => ({
        section: s.section,
        excerpt: typeof s.content === "string" ? s.content.slice(0, 800) : ""
      }))
    : [];

  return {
    docsOk: docs.ok,
    docsError: docs.ok ? null : docs.error,
    recoveryHits,
    skillOk: walletIntegration.ok,
    skillError: walletIntegration.ok ? null : walletIntegration.error,
    skillExtract
  };
}

