async () => {
  const [rfps, docs] = await Promise.all([
    scout.getRfps({ limit: 100 }),
    stellarDocs.search_wallet_dapp_docs({ query: 'passkeys smart accounts', hitsPerPage: 5, includeContent: false })
  ]);

  const now = new Date().toISOString();
  const rfpsRows = rfps.ok && rfps.data ? rfps.data : null;
  const docsHits = docs.ok && docs.data ? docs.data.hits || docs.data.results || [] : [];

  const normalized = Array.isArray(rfpsRows) ? rfpsRows : (rfpsRows && rfpsRows.rfps) ? rfpsRows.rfps : [];
  const open = normalized.filter(r => {
    const status = String(r.status || r.state || r.open_status || '').toLowerCase();
    return status.includes('open') || status === 'active' || status === 'accepting' || status === 'live';
  });

  const keywordMatch = open.filter(r => {
    const text = [r.title, r.description, r.summary, r.category, r.tags && r.tags.join(' ')].filter(Boolean).join(' ').toLowerCase();
    return text.includes('passkey') || text.includes('smart account') || text.includes('account abstraction') || text.includes('wallet');
  }).slice(0, 8).map(r => ({
    id: r.id || r.slug || null,
    title: r.title || r.name || null,
    status: r.status || r.state || null,
    category: r.category || null,
    deadline: r.deadline || r.dueDate || r.closing_date || null,
    url: r.url || r.link || null
  }));

  return {
    currentAsOf: now,
    openRfpCount: open.length,
    matchingOpenRfps: keywordMatch,
    docsSignals: docsHits.slice(0, 5).map(h => ({ title: h.title || h.name || null, url: h.url || null, snippet: h.snippet || null }))
  };
}

