async () => {
  const res = await scout.searchProjects({ query: 'development activity', limit: 50 });
  if (!res.ok) return { error: res.error };
  const projects = (res.data.projects || []).map(p => ({
    name: p.name,
    slug: p.slug,
    category: p.category,
    status: p.status,
    activity: p.activity || p.development_activity || p.dev_activity || null,
    recentCommits: p.recentCommits || p.commits_30d || p.commits30d || null,
    stars: p.stars || null,
    contributors: p.contributors || null,
    source: 'scout.searchProjects'
  }));
  const scored = projects.map(p => {
    const basis = p.activity ?? p.recentCommits ?? 0;
    return { ...p, basis };
  }).sort((a, b) => (b.basis || 0) - (a.basis || 0));
  return {
    totalReturned: scored.length,
    top5: scored.slice(0, 5).map(p => ({
      name: p.name,
      slug: p.slug,
      category: p.category,
      status: p.status,
      activityBasis: p.activity !== null ? `activity=${p.activity}` : p.recentCommits !== null ? `recentCommits=${p.recentCommits}` : 'activity field not exposed in list row',
      source: p.source
    }))
  };
}

