async () => {
  const [repos, activity] = await Promise.all([
    scout.searchRepos({ query: 'ZK Soroban', limit: 8 }),
    codemode.skill.read('skills.stellar-light.stellar-scout#companion-skills', { sections: ['stellar-developer-activity'] })
  ]);

  const repoRows = repos.ok && repos.data && Array.isArray(repos.data.repos)
    ? repos.data.repos.map(r => ({
        name: r.name || r.fullName || r.repo || r.slug,
        url: r.url || r.htmlUrl || r.homepage,
        description: r.description,
        language: r.language,
        stars: r.stars,
        forks: r.forks,
        updatedAt: r.updatedAt || r.pushedAt || r.lastActivityAt
      }))
    : [];

  let caveat = null;
  if (activity.ok) {
    const text = activity.content || (activity.sections && activity.sections['stellar-developer-activity']) || '';
    caveat = text.split('\n').filter(Boolean).slice(0, 8).join(' ');
  }

  return {
    repos: repoRows.slice(0, 6),
    repoSearch: repos.ok ? { total: repos.data.total, note: repos.data.note || null } : repos.error,
    activityCaveat: caveat
  };
}

