async () => {
  const checkedAt = new Date().toISOString();
  const [rfpsRes, similarRes] = await Promise.all([
    scout.getRfps({ limit: 100 }),
    lumenloop.find_similar_scf_submissions({ query: "passkeys smart accounts WebAuthn wallet", limit: 8 })
  ]);

  const pickArray = (payload) => {
    if (!payload || typeof payload !== "object") return [];
    for (const key of ["rfps", "items", "results", "data"]) {
      if (Array.isArray(payload[key])) return payload[key];
    }
    for (const value of Object.values(payload)) {
      if (Array.isArray(value)) return value;
    }
    return [];
  };

  const textOf = (x) => JSON.stringify(x || {}).toLowerCase();
  const isOpen = (x) => {
    const s = String(x.status || x.state || x.phase || x.open_status || x.deadline_status || "").toLowerCase();
    if (s.includes("closed") || s.includes("past") || s.includes("ended")) return false;
    if (s.includes("open") || s.includes("active")) return true;
    if (typeof x.isOpen === "boolean") return x.isOpen;
    if (typeof x.open === "boolean") return x.open;
    return false;
  };
  const isRelevant = (x) => {
    const t = textOf(x);
    return ["passkey", "webauthn", "smart account", "smart wallet", "account abstraction"].some(k => t.includes(k));
  };
  const project = (x) => ({
    id: x.id || x.slug || x.key || null,
    title: x.title || x.name || x.headline || null,
    status: x.status || x.state || x.phase || x.open_status || null,
    category: x.category || x.track || null,
    url: x.url || x.link || x.href || null,
    deadline: x.deadline || x.dueDate || x.endsAt || x.closeDate || null,
    summary: x.summary || x.description || x.brief || null
  });

  const allRfps = rfpsRes.ok ? pickArray(rfpsRes.data) : [];
  const openRfps = allRfps.filter(isOpen);
  const relatedOpenRfps = openRfps.filter(isRelevant).map(project).slice(0, 10);
  const allRelatedRfps = allRfps.filter(isRelevant).map(project).slice(0, 10);

  const similarRows = similarRes.ok ? pickArray(similarRes.data).map(x => ({
    title: x.title || x.name || null,
    round: x.round || null,
    category: x.category || null,
    award_type: x.award_type || x.awardType || null,
    slug: x.slug || null
  })).slice(0, 5) : [];

  return {
    checkedAt,
    rfps: rfpsRes.ok ? {
      totalFetched: allRfps.length,
      openCount: openRfps.length,
      relatedOpenCount: relatedOpenRfps.length,
      relatedOpenRfps,
      relatedRfpsRegardlessOfStatus: allRelatedRfps,
      payloadKeys: Object.keys(rfpsRes.data || {})
    } : { error: rfpsRes.error },
    similarScfSubmissionsForContext: similarRes.ok ? { count: similarRows.length, rows: similarRows } : { error: similarRes.error }
  };
}

