async () => {
  const desc = await codemode.describe("scout.searchProjects");
  const cats = ["Infrastructure", "Tooling", "User-Facing App", "Protocol/Contract", "Anchor"];
  const calls = {};
  await Promise.all(cats.map(async (category) => {
    calls[category] = await scout.searchProjects({ query: "Stellar", category, limit: 50 });
  }));

  const rows = [];
  for (const [category, r] of Object.entries(calls)) {
    if (!r.ok) continue;
    const data = r.data || {};
    const list = data.projects || data.results || data.items || data.data || [];
    for (const p of list) {
      const dev = p.developmentActivity || p.devActivity || p.activity || p.github || p.repository || p.repo || p.repositories || {};
      const github = p.github || p.githubUrl || p.repoUrl || p.repositoryUrl || p.repository || p.repo || dev.github || dev.url || null;
      const signals = {
        commits30d: p.commits30d ?? p.commits_30d ?? p.recentCommits ?? dev.commits30d ?? dev.recentCommits ?? null,
        commits90d: p.commits90d ?? p.commits_90d ?? dev.commits90d ?? null,
        lastCommit: p.lastCommit ?? p.lastCommitAt ?? p.last_commit_at ?? dev.lastCommit ?? dev.lastCommitAt ?? null,
        stars: p.stars ?? p.githubStars ?? dev.stars ?? null,
        forks: p.forks ?? p.githubForks ?? dev.forks ?? null,
        contributors: p.contributors ?? p.githubContributors ?? dev.contributors ?? null,
        openIssues: p.openIssues ?? p.githubOpenIssues ?? dev.openIssues ?? null,
        status: p.status ?? p.liveStatus ?? p.activeStatus ?? null
      };
      const name = p.name || p.title || p.projectName || p.slug;
      if (!name) continue;
      rows.push({ name, slug: p.slug || null, category: p.category || category, description: p.description || p.summary || null, github, signals, rawKeys: Object.keys(p).slice(0, 20) });
    }
  }

  const byName = new Map();
  for (const row of rows) {
    const key = (row.slug || row.name).toLowerCase();
    const prev = byName.get(key);
    if (!prev || JSON.stringify(row.signals).length > JSON.stringify(prev.signals).length) byName.set(key, row);
  }

  const scored = Array.from(byName.values()).map((r) => {
    const s = r.signals;
    let score = 0;
    if (typeof s.commits30d === "number") score += s.commits30d * 100;
    if (typeof s.commits90d === "number") score += s.commits90d * 20;
    if (s.lastCommit) {
      const t = Date.parse(s.lastCommit);
      if (!Number.isNaN(t)) score += Math.max(0, 365 - (Date.now() - t) / 86400000);
    }
    if (typeof s.contributors === "number") score += s.contributors * 5;
    if (typeof s.stars === "number") score += Math.log10(s.stars + 1) * 10;
    return { ...r, score: Math.round(score * 10) / 10 };
  }).filter(r => r.github || Object.values(r.signals).some(v => v !== null));

  scored.sort((a, b) => b.score - a.score || (b.signals.commits30d || 0) - (a.signals.commits30d || 0));

  return {
    described: desc.ok ? { id: desc.id, usage: desc.usage, outputTop: Object.keys(desc.outputSchema?.properties || {}) } : desc,
    source: "scout.searchProjects fanout by category; ranking uses returned development/GitHub fields when present",
    searchedCategories: cats,
    projectCountWithActivitySignals: scored.length,
    top5: scored.slice(0, 5).map(({ name, slug, category, description, github, signals, score }) => ({ name, slug, category, description, github, signals, score })),
    callErrors: Object.fromEntries(Object.entries(calls).filter(([k, v]) => !v.ok).map(([k, v]) => [k, v.error]))
  };
}

