async () => {
  const desc = await codemode.describe("scout.searchRepos");
  const queries = [
    { label: "zk soroban", input: { q: "zk soroban", limit: 12 } },
    { label: "zero knowledge soroban", input: { q: "zero knowledge soroban", limit: 12 } },
    { label: "zkp soroban rust", input: { q: "zkp soroban", language: "Rust", limit: 12 } },
    { label: "noir soroban", input: { q: "noir soroban", limit: 8 } },
    { label: "groth16 soroban", input: { q: "groth16 soroban", limit: 8 } }
  ];
  const results = await Promise.all(queries.map(async x => ({ label: x.label, result: await scout.searchRepos(x.input) })));

  const rows = [];
  for (const { label, result } of results) {
    if (!result.ok) {
      rows.push({ _errorFor: label, error: result.error });
      continue;
    }
    const arr = result.data.repos || result.data.items || result.data.results || result.data.repositories || [];
    for (const r of arr) {
      const fullName = r.fullName || r.full_name || r.repo || r.nameWithOwner || (r.owner && r.name ? `${r.owner}/${r.name}` : r.name);
      if (!fullName) continue;
      rows.push({
        query: label,
        fullName,
        url: r.url || r.htmlUrl || r.html_url || r.githubUrl,
        description: r.description || r.summary,
        language: r.language || r.primaryLanguage,
        stars: r.stars ?? r.stargazers_count ?? r.starCount,
        forks: r.forks ?? r.forks_count ?? r.forkCount,
        quality: r.quality ?? r.score ?? r.rankScore,
        topics: r.topics,
        updatedAt: r.updatedAt || r.updated_at || r.pushedAt || r.pushed_at,
        lastCommitAt: r.lastCommitAt || r.last_commit_at,
        activity: r.activity || r.activityScore || r.recentActivity,
        matchedTerms: r.matchedTerms || r.matches
      });
    }
  }

  const seen = new Map();
  for (const r of rows.filter(x => !x._errorFor)) {
    const key = r.fullName.toLowerCase();
    const prev = seen.get(key);
    if (!prev) seen.set(key, { ...r, queries: [r.query] });
    else {
      prev.queries = Array.from(new Set([...(prev.queries || []), r.query]));
      prev.stars = Math.max(prev.stars || 0, r.stars || 0) || prev.stars || r.stars;
      prev.forks = Math.max(prev.forks || 0, r.forks || 0) || prev.forks || r.forks;
      prev.quality = Math.max(prev.quality || 0, r.quality || 0) || prev.quality || r.quality;
      prev.updatedAt = prev.updatedAt || r.updatedAt;
      prev.lastCommitAt = prev.lastCommitAt || r.lastCommitAt;
      prev.activity = prev.activity || r.activity;
      if (!prev.description && r.description) prev.description = r.description;
      if (!prev.url && r.url) prev.url = r.url;
    }
  }

  const deduped = Array.from(seen.values()).map(r => {
    const text = `${r.fullName} ${r.description || ""} ${(r.topics || []).join(" ")}`.toLowerCase();
    const zkHit = /\bzk\b|zero.?knowledge|zkp|noir|groth|plonk|snark|stark|risc0|risc\s*zero|sp1/.test(text);
    const sorobanHit = /soroban|stellar/.test(text);
    const signal = (r.queries?.length || 1) * 10 + (Number(r.stars) || 0) + (Number(r.forks) || 0) * 2 + (zkHit ? 20 : 0) + (sorobanHit ? 20 : 0) + (Number(r.quality) || 0) / 10;
    return { ...r, zkHit, sorobanHit, signal: Math.round(signal * 10) / 10 };
  }).filter(r => r.zkHit && r.sorobanHit)
    .sort((a,b) => b.signal - a.signal)
    .slice(0, 8);

  return {
    searchReposUsage: desc.ok ? desc.usage : desc.error,
    outputTopLevel: desc.ok ? Object.keys(desc.outputSchema?.properties || {}) : [],
    queryStatuses: results.map(x => ({ label: x.label, ok: x.result.ok, count: x.result.ok ? ((x.result.data.repos || x.result.data.items || x.result.data.results || x.result.data.repositories || []).length) : null, error: x.result.ok ? null : x.result.error })),
    repos: deduped.map(r => ({ fullName: r.fullName, url: r.url, description: r.description, language: r.language, stars: r.stars, forks: r.forks, updatedAt: r.updatedAt, lastCommitAt: r.lastCommitAt, activity: r.activity, quality: r.quality, queries: r.queries, signal: r.signal })),
    caveat: "Rows are from scout.searchRepos list results only; absence of updatedAt/lastCommitAt/activity fields in a row means this answer cannot verify freshness from the returned payload."
  };
}

