  const rows = Array.isArray(data?.hits) ? data.hits : Array.isArray(data) ? data : [];

  const selected = rows.slice(0, 8).map((h) => ({
    title: h.title || h.hierarchy?.lvl0 || h.hierarchy?.lvl1 || h.url || "Untitled",
    url: h.url,
    snippet: (h.snippet || h.content || h.text || "").replace(/\s+/g, " ").slice(0, 500)
  }));

  const joined = selected.map(x => `${x.title} ${x.snippet}`).join("\n").toLowerCase();
  const patterns = [
    { name: "Keypair/secret-key based accounts", evidence: joined.includes("secret key") || joined.includes("keypair") || joined.includes("seed") },
    { name: "Muxed accounts for user-level routing under a custodial account", evidence: joined.includes("muxed") || joined.includes("memo") },
    { name: "SEP-24/anchor wallet flows for deposits and withdrawals", evidence: joined.includes("sep-24") || joined.includes("deposit") || joined.includes("withdraw") || joined.includes("anchor") },
