async () => {
  // Read the Soroswap entity focus section from the Stellar ecosystem digest skill
  const entityFocus = await codemode.skill.read('skills.lumenloop.stellar-ecosystem-digest', { sections: ['pass-3-entity-focus'] });
  const entitiesWatch = await codemode.skill.read('skills.lumenloop.stellar-ecosystem-digest', { sections: ['entities-to-watch'] });
  // Helper to extract plain text from markdown (very naive)
  const extract = (text) => {
    if (!text) return '';
    // Remove markdown headings and links, keep lines
    return text.replace(/[#>*`]/g, '').replace(/\[([^\]]+)\]\([^\)]+\)/g, '$1').trim();
  };
  const focusText = entityFocus.ok && entityFocus.content ? extract(entityFocus.content) : '';
  const watchText = entitiesWatch.ok && entitiesWatch.content ? extract(entitiesWatch.content) : '';
  // Combine and look for Soroswap lines
  const combined = `${focusText}\n${watchText}`;
  // Simple regex to capture description and builder
  const lines = combined.split('\n').filter(l => l.toLowerCase().includes('soroswap'));
  // If multiple lines, pick first
  const soroswapLine = lines.length ? lines[0] : '';
  // Try to parse builder name after "by" or "from"
  let description = '';
  let builder = '';
  if (soroswapLine) {
    // Example pattern: "Soroswap is a decentralized AMM on Stellar built by XYZ."
    const match = soroswapLine.match(/Soroswap[^.]*\./i);
    description = match ? match[0].trim() : soroswapLine.trim();
    const builderMatch = soroswapLine.match(/by\s+([A-Za-z0-9_-]+)/i) || soroswapLine.match(/from\s+([A-Za-z0-9_-]+)/i);
    if (builderMatch) builder = builderMatch[1];
  }
  // Fallback: if not found, just return raw lines
  return { description, builder, rawLines: lines.slice(0, 3) };
}

async () => {
  // Get full signature for search_directory to know output fields
  const desc = await codemode.describe('lumenloop.search_directory');
  // Perform directory search for Soroswap
  const dir = await lumenloop.search_directory({ query: 'Soroswap', limit: 5 });
  let description = '';
  let builder = '';
  if (dir.ok && Array.isArray(dir.data.projects) && dir.data.projects.length) {
    // Find first project where title includes Soroswap (case-insensitive)
    const proj = dir.data.projects.find(p => (p.title || '').toLowerCase().includes('soroswap'));
    if (proj) {
      description = proj.description || '';
      // Use website or tags as builder hint; sometimes builder name is in title or description
      builder = proj.website || '';
      // If website empty, try to extract builder name from description (e.g., "by XYZ")
      if (!builder && description) {
        const m = description.match(/by\s+([A-Za-z0-9_-]+)/i) || description.match(/from\s+([A-Za-z0-9_-]+)/i);
        if (m) builder = m[1];
      }
    }
  }
  // If still empty, fallback to scout project search
  if (!description) {
    const scoutRes = await scout.searchProjects({ category: undefined, limit: 5, query: 'Soroswap' });
    if (scoutRes.ok && Array.isArray(scoutRes.data.projects) && scoutRes.data.projects.length) {
      const p = scoutRes.data.projects[0];
      description = p.description || '';
      builder = p.builder || p.website || '';
    }
  }
  return { description, builder };
}

